import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';

const Login: React.FC = () => {
  const [email, setEmail] = useState('admin@granja.com');
  const [password, setPassword] = useState('admin123');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      await login(email, password);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Error de conexión');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '20px'
    }}>
      <div style={{
        background: 'rgba(255, 255, 255, 0.95)',
        backdropFilter: 'blur(10px)',
        borderRadius: '20px',
        padding: '40px',
        width: '100%',
        maxWidth: '450px',
        boxShadow: '0 20px 40px rgba(0,0,0,0.1)',
        border: '1px solid rgba(255,255,255,0.2)'
      }}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '40px' }}>
          <div style={{ 
            fontSize: '80px', 
            marginBottom: '20px',
            background: 'linear-gradient(135deg, #667eea, #764ba2)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            backgroundClip: 'text'
          }}>
            🐷
          </div>
          <h1 style={{ 
            color: '#2c3e50', 
            marginBottom: '10px',
            fontSize: '28px',
            fontWeight: '700'
          }}>
            Sistema de Gestión Porcina
          </h1>
          <p style={{ 
            color: '#7f8c8d',
            fontSize: '16px',
            margin: 0
          }}>
            Tecnología avanzada para tu granja
          </p>
        </div>

        {error && (
          <div className="alert alert-danger" style={{ marginBottom: '25px' }}>
            <span style={{ fontSize: '18px', marginRight: '8px' }}>⚠️</span>
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="email" style={{ 
              fontSize: '14px',
              fontWeight: '600',
              color: '#2c3e50',
              marginBottom: '8px',
              display: 'block'
            }}>
              📧 Correo Electrónico
            </label>
            <input
              type="email"
              id="email"
              className="form-control"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              disabled={loading}
              style={{
                padding: '15px 20px',
                fontSize: '16px',
                border: '2px solid #e9ecef',
                borderRadius: '12px',
                transition: 'all 0.3s ease'
              }}
              placeholder="Ingresa tu email"
            />
          </div>

          <div className="form-group">
            <label htmlFor="password" style={{ 
              fontSize: '14px',
              fontWeight: '600',
              color: '#2c3e50',
              marginBottom: '8px',
              display: 'block'
            }}>
              🔒 Contraseña
            </label>
            <input
              type="password"
              id="password"
              className="form-control"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              disabled={loading}
              style={{
                padding: '15px 20px',
                fontSize: '16px',
                border: '2px solid #e9ecef',
                borderRadius: '12px',
                transition: 'all 0.3s ease'
              }}
              placeholder="Ingresa tu contraseña"
            />
          </div>

          <button
            type="submit"
            className="btn btn-primary"
            style={{ 
              width: '100%',
              padding: '15px',
              fontSize: '16px',
              fontWeight: '600',
              borderRadius: '12px',
              background: 'linear-gradient(135deg, #667eea, #764ba2)',
              border: 'none',
              marginTop: '10px',
              minHeight: '54px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '10px'
            }}
            disabled={loading}
          >
            {loading ? (
              <>
                <div className="loading-spinner" style={{ 
                  width: '20px', 
                  height: '20px',
                  borderWidth: '2px'
                }}></div>
                Ingresando...
              </>
            ) : (
              <>
                🚀 Ingresar al Sistema
              </>
            )}
          </button>
        </form>

        {/* Credenciales por defecto */}
        <div style={{ 
          marginTop: '30px', 
          padding: '20px', 
          background: 'linear-gradient(135deg, #f8f9fa, #e9ecef)', 
          borderRadius: '12px',
          border: '1px solid #dee2e6'
        }}>
          <div style={{ 
            display: 'flex', 
            alignItems: 'center', 
            marginBottom: '12px',
            color: '#495057'
          }}>
            <span style={{ fontSize: '20px', marginRight: '8px' }}>💡</span>
            <strong>Credenciales de Demostración</strong>
          </div>
          <div style={{ fontSize: '14px', color: '#6c757d', lineHeight: '1.6' }}>
            <div style={{ marginBottom: '5px' }}>
              <strong>Email:</strong> admin@granja.com
            </div>
            <div>
              <strong>Contraseña:</strong> admin123
            </div>
          </div>
        </div>

        {/* Footer */}
        <div style={{ 
          textAlign: 'center', 
          marginTop: '30px',
          paddingTop: '20px',
          borderTop: '1px solid #e9ecef'
        }}>
          <p style={{ 
            color: '#7f8c8d', 
            fontSize: '12px',
            margin: 0
          }}>
            © 2025 Sistema de Gestión Porcina v1.0
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
